package com.hospital.management.controller.admin;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.PatientServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.Optional;
@WebServlet("/admin/patients/edit")public class PatientEditServlet extends HttpServlet{private final PatientService service;public PatientEditServlet(){this(new PatientServiceImpl());}public PatientEditServlet(PatientService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=Form.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Optional<Patient>p=service.getPatient(id);if(p.isEmpty()){r.sendError(404);return;}show(q,r,Form.patient(p.get()),p.get().getUserId()!=null);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setCharacterEncoding("UTF-8");Long id=Form.id(q.getParameter("patientId"));if(id==null){r.sendError(400);return;}PatientForm f=Form.patient(q,id);ServiceResult<Void>x=service.updatePatient(f,RequestUtil.buildAuditContext(q));Form.clearPasswords(f);if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/patients?message=updated");return;}if(x.getStatus()==ServiceResult.Status.NOT_FOUND){r.sendError(404);return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f,"true".equals(q.getParameter("linkedAccount")));}private void show(HttpServletRequest q,HttpServletResponse r,PatientForm f,boolean linked)throws ServletException,IOException{q.setAttribute("formMode","EDIT");q.setAttribute("patientForm",f);q.setAttribute("linkedAccount",linked);q.getRequestDispatcher("/WEB-INF/views/admin/patients/form.jsp").forward(q,r);}}
